 1	import React from 'react';
 2	import { useTranslation } from 'react-i18next';
 3	import { TENANTS } from '../tenants';
 4	import { TestIds } from '../test-ids';
 5	import {
 6	  MenuToggle,
 7	  MenuToggleElement,
 8	  Select,
 9	  SelectList,
10	  SelectOption,
11	} from '@patternfly/react-core';
12	import { isOption } from './filters/filters-from-params';
13	
14	interface TenantDropdownProps {
15	  selectedTenant?: string;
16	  onTenantSelected?: (tenant: string) => void;
17	  isDisabled?: boolean;
18	}
19	
20	export const TenantDropdown: React.FC<TenantDropdownProps> = ({
21	  selectedTenant,
22	  onTenantSelected,
23	  isDisabled = false,
24	}) => {
25	  const { t } = useTranslation('plugin__logging-view-plugin');
26	
27	  const [isOpen, setIsOpen] = React.useState(false);
28	
29	  const selectRef = React.useRef<HTMLDivElement>(null);
30	
31	  const onToggle = () => setIsOpen(!isOpen);
32	  const onSelect = (
33	    _: React.MouseEvent<Element, MouseEvent> | undefined,
34	    value: string | number | undefined,
35	  ) => {
36	    const selectedValue = isOption(value) ? value.value : String(value);
37	    setIsOpen(false);
38	    if (selectedValue) {
39	      onTenantSelected?.(selectedValue);
40	    }
41	  };
42	
43	  const handleClickOutside = (event: MouseEvent) => {
44	    if (isOpen && !selectRef.current?.contains(event.target as Node)) {
45	      setIsOpen(false);
46	    }
47	  };
48	
49	  React.useEffect(() => {
50	    if (isOpen) {
51	      window.addEventListener('click', handleClickOutside);
52	    }
53	    return () => {
54	      window.removeEventListener('click', handleClickOutside);
55	    };
56	  }, [isOpen]);
57	
58	  const toggle = (toggleRef: React.Ref<MenuToggleElement>) => (
59	    <MenuToggle
60	      isDisabled={isDisabled}
61	      ref={toggleRef}
62	      onClick={onToggle}
63	      isExpanded={isOpen}
64	      data-test={TestIds.TenantToggle}
65	    >
66	      {selectedTenant}
67	    </MenuToggle>
68	  );
69	
70	  return (
71	    <div ref={selectRef}>
72	      <Select
73	        id="logging-view-tenant-dropdown"
74	        isOpen={isOpen}
75	        onSelect={onSelect}
76	        placeholder={t('Select a tenant')}
77	        toggle={toggle}
78	      >
79	        <SelectList>
80	          {TENANTS.map((tenant) => (
81	            <SelectOption key={tenant} value={tenant} isSelected={selectedTenant === tenant}>
82	              {tenant}
83	            </SelectOption>
84	          ))}
85	        </SelectList>
86	      </Select>
87	    </div>
88	  );
89	};

